CONFIRMED WORKING RECIPE (jsPDF 3.0.4, doc created exactly as pdf-assembler.ts:90 does: new jsPDF({orientation, unit:'mm', format})).

// --- constants from the doc ---
const K = pdf.internal.scaleFactor;               // 72/25.4 for mm
const H_MM = pdf.internal.pageSize.getHeight();   // 210.0015... for A4 landscape
const Matrix = pdf.Matrix;                        // === jsPDF.API.Matrix
const TilingPattern = pdf.TilingPattern;          // === jsPDF.API.TilingPattern (also a named export)

// --- 1. DEFINE the pattern (must be in ADVANCED; definition is apiMode-scoped, storage is not) ---
const CELL = 6; // authored in mm
const stripes = new TilingPattern([0, 0, CELL, CELL], CELL, CELL, null, null); // matrix = null!
pdf.advancedAPI(() => {
  pdf.beginTilingPattern(stripes);
  // Inside the cell apiMode is ADVANCED => coords are RAW pattern-space units (no scaleFactor,
  // no Y-flip). So "6" here means 6 pattern units, and our /Matrix below supplies the mm->pt scale.
  pdf.setFillColor(220, 40, 40);  pdf.rect(0, 0, CELL, CELL / 2, 'F');
  pdf.setFillColor(250, 220, 220); pdf.rect(0, CELL / 2, CELL, CELL / 2, 'F');
  pdf.endTilingPattern('stripes', stripes);
});
// Image cell: identical, just addImage(dataUrl,'PNG',0,0,CELL,CELL,undefined,'NONE') inside.
// jsPDF emits its own "1 0 0 -1 0 0 cm" so the bitmap is upright. The image XObject is
// auto-included in the pattern's own /Resources. No manual flip required.

// --- 2. MATRIX MATH (this is the whole trick) ---
// jsPDF row-vector convention: A.multiply(B) === B*A  (apply B first, then A).
// fillWithPattern (jspdf.node.js:5154-5167) does: final = flip.multiply(patternData.matrix)
//                                                       === patternData.matrix * flip
// with flip F = Matrix(1,0,0,-1,0,getPageHeight())   <-- mm-VALUED, see gotcha #1.
// F is an involution (F*F = I), so to make the emitted /Matrix equal any target M_final,
// pre-multiply by F and let jsPDF re-apply it:
const F = () => new Matrix(1, 0, 0, -1, 0, H_MM);
// mm (Y-down, origin top-left)  ->  PDF default user space (points, Y-up, origin bottom-left)
const T = () => new Matrix(K, 0, 0, -K, 0, H_MM * K);

function patternMatrixFor(ax, ay, deg) {   // anchor page-mm + visual-clockwise angle
  const r = (deg * Math.PI) / 180, c = Math.cos(r), s = Math.sin(r);
  const A = new Matrix(c, s, -s, c, ax, ay);  // cell (u,v) -> page-mm, Y-down
  const M_final = T().multiply(A);            // === A * T   (apply A, then T)
  return F().multiply(M_final);               // === M_final * F ; jsPDF re-applies F -> M_final
}

// --- 3. BUILD the path with ZERO paint op, then pattern-fill (plain COMPAT mode, mm, Y-down) ---
function polygon(pts) {  // pts = [[x,y],...] page-mm
  const [x0, y0] = pts[0];
  const segs = pts.slice(1).map(([x, y], i) => [x - pts[i][0], y - pts[i][1]]);
  pdf.lines(segs, x0, y0, [1, 1], null, true);  // style === null is MANDATORY in COMPAT
}
polygon([[20, 30], [90, 20], [110, 80], [40, 90]]);   // slanted parallelogram
pdf.fillEvenOdd({
  key: 'stripes',
  matrix: patternMatrixFor(20, 20, 0),   // or 30 for a rotated pattern
  boundingBox: [0, 0, CELL, CELL], xStep: CELL, yStep: CELL,
});

VERIFICATION OF THE MATRIX MATH (analytic == emitted): for anchor (20,20) deg 0, M_final should be
[K,0,0,-K, 20*K, (H_MM-20)*K] = [2.8346, 0, 0, -2.8346, 56.6929, 538.5871]. The PDF contains exactly
"/Matrix [2.8346456692913389 0. 0. -2.8346456692913389 56.6929133858267775 538.5870866141732449]".
Reading it back: 538.587/2.8346 = 190.0 => 210.0016-190.0 = 20mm from the top. Anchored correctly.
Determinant of the rotation block is -K^2 (negative) => the Y-flip is baked in, so positive `deg`
reads as visual clockwise on the page, matching screen convention. Confirmed in the raster render.
